import { Component, Prop, Element, h, Host } from '@stencil/core';

const BadgeConversionMap: Record<string, any> = {
  inverse: { kind: 'prominent', palette: 'accent', variant: 'fill' },
  brand: { kind: 'prominent', palette: 'brand', variant: 'fill' },
  informative: { kind: 'prominent', palette: 'informative', variant: 'fill' },
  positive: { kind: 'prominent', palette: 'positive', variant: 'fill' },
  negative: { kind: 'prominent', palette: 'negative', variant: 'fill' },
  special: { kind: 'prominent', palette: 'special', variant: 'fill' },
  callout: { kind: 'prominent', palette: 'callout', variant: 'fill' }
};

/**
 * A kds-badge displays a numeric value that represents a quantity of items or elements.
 */
@Component({
  tag: "kds-badge",
  styleUrl: "kds-badge.css",
  shadow: false
})
export class KdsBadge {
  @Element() hostEl: HTMLKdsBadgeElement;

  /** The numeric value to display. */
  @Prop() readonly count?: number;
  /** Sets the color palette. */
  // prettier-ignore
  @Prop({ mutable: true }) palette: "neutral" | "brand" | "accent" | "positive" | "negative" | "informative" | "callout" | "special" = "brand";
  /** Sets the color kind. */
  @Prop({ mutable: true }) kind: "dominant" | "prominent" | "subtle" | "alternate" = "dominant";
  /** Applies the inverse color styling. */
  @Prop() readonly inverse: boolean = false;
  /** Sets the badge's icon */
  @Prop() readonly icon?: string;
  /** Sets the badge's text */
  @Prop() readonly text?: string;

  private isHydrated: boolean = false;

  private outputElement: HTMLOutputElement;

  componentDidLoad() {
    this.isHydrated = true;
  }

  componentWillLoad() {
    if (BadgeConversionMap[this.kind]) {
      this.palette = BadgeConversionMap[this.kind].palette;
      this.kind = BadgeConversionMap[this.kind].kind;
    }
  }

  render() {
    let {
      count,
      palette,
      kind,
      inverse,
      outputElement,
      isHydrated,
      hostEl,
      text,
      icon
    } = this;

    const Icon = this.icon;
    const classes = {
      "kds-Badge": true,
      "kds-Badge--pinned": isHydrated
        ? outputElement && outputElement.children.length > 1
        : hostEl.children.length > 0,
      [`palette-${palette}`]: true,
      [`kind-${kind}`]: true,
      "variant-fill": true,
      distinct: true,
      "as-inverse": inverse,
      "kds-Badge--withIcon": icon !== undefined
    };

    return (
      <Host
        role='status'
        class='kds-Badge-wrapper'
        ref={(el: HTMLOutputElement) => {
          this.outputElement = el;
        }}
      >
        <slot />
        {count !== undefined ? (
          <span
            class={{
              ...classes
            }}
          >
            {count}
          </span>
        ) : text !== undefined ? (
          <span
            class={{
              ...classes
            }}
          >
            {text}
          </span>
        ) : icon !== undefined ? (
          <span
            class={{
              ...classes
            }}
          >
            <Icon />
          </span>
        ) : (
          ""
        )}
      </Host>
    );
  }
}
